const body = $input.first().json.body || $input.first().json;

const nombre = body.nombre || '';
const email = body.email || '';
const telefono = body.telefono || '';
const fecha_evento = body.fecha_evento || '';
const tipo_evento = body.tipo_evento || '';
const paquete_asignado = body.paquete_asignado || '';

// Generar folio LC-DDMM-XXX
const now = new Date();
const dd = String(now.getDate()).padStart(2,'0');
const mm = String(now.getMonth() + 1).padStart(2,'0');
const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
let suffix = '';
for (let i = 0; i < 3; i++) {
  suffix += chars[Math.floor(Math.random() * chars.length)];
}
const folio = 'LC-' + dd + mm + '-' + suffix;

// Generar token UUID v4
const token = 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
  const r = Math.random() * 16 | 0;
  const v = c === 'x' ? r : (r & 0x3 | 0x8);
  return v.toString(16);
});

const link = 'https://lacabanaeventos.com/seleccion-menu.html?token=' + token;
const fecha_generacion = now.toLocaleString('es-MX', { timeZone: 'America/Mexico_City' });

return [{ json: {
  folio,
  token,
  link,
  nombre,
  email,
  telefono,
  fecha_evento,
  tipo_evento,
  paquete_asignado,
  status: 'pendiente',
  fecha_generacion,
  menu_elegido: '',
  num_invitados: '',
  cocteleria: '',
  cerveza_barril: '',
  dietas_especiales: '',
  notas_cliente: '',
  fecha_seleccion: ''
}}];
